INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (930, 177899, 1, 1469, '瓶子', '那天有人和我谈到星座，然后转头对我说：“瓶子，是不是水瓶座？”
<br>说到瓶子顾名思义就是水瓶座，对我就是水瓶座的，所以将自己的名字取为瓶子。
<br>女水瓶和男水瓶都是一样的，个性真的是太像了，所以也就有时候会互相吸引的原因。我就认识这么一个男水瓶，他很固执、任性还有那么一点点的孩子气，他会在心情不好的时候打开QQ将里面所有人都拉入黑名单，等过后再一个一个的问人家QQ从新加入，他还对那些被他删除了的人说是因为他心情不好才删了他们的，这最让人哭笑不得。他还会很反复无常，答应了你的事过后不到30分钟又会反悔不承认，让你一个人在那里生气，他却在一旁大笑，好像和他一点关系都没有，显得很绝情。而且他也会将自己的思想完完全全的表现在你的面前，不容你的反驳。可当你见到他的时候你完全不能把他和那个叫你气得咬牙切齿的人联想在一起，因为见他的时候他一路上都在笑，满脸上都是笑容。傻傻的看着你，你一点也生气不起来。这样的人真的和我太像了，简直就是自己的翻版，有时候真的会被他这样的性格所吸引。因为水瓶座的人都有颗猫般好奇的心，所以对于那种自己摸不透的人是最吸引他的。
<br>其实我就是一个完全水瓶座的人，只要是瓶子应该具有的特性我都具有了。冷酷、绝情、怪异、独立、好奇、观察敏锐、思想新颖、有创意等，这些我都具备了。
<br>水瓶座的我也具有了水瓶人的博爱，也因为这样身边到处都有很多喜欢自己的人，朋友很多；然而我最不能容许自己的感情的不明不白，就算是会伤了他人的心我也要将心里的感觉说出来，我宁愿绝情一点也不愿意暧昧不明；同样的，如果我喜欢一个人的话，那么我也会将这个心意表明出来，我不想拖泥带水，就算不被喜欢也好，我也会很自动的退下。这就是瓶子的个性不喜欢拖泥带水有什么就说什么，想什么就做什么，很果断。我也不去否认有很多人都被我这样的个性所伤害到，但是，也不可说我就没有一点的好处，至少我所知道的是我所有的朋友都很喜欢和我分享他们的心事，我就是有那种可以让人信任的力量，而我也真的很理性的去做许多事情。虽然自己也会被别人说不成熟，但是我对朋友很好，所以大家也很信任我。瓶子很重感情的。
<br>自己是最知道自己的，自己是一个很感性的人，什么事情都会写在脸上，当我快乐、悲伤、犹豫、踌躇时，脸上都会出现这些心情对应的脸色；而且当我生气的时候，不管有什么高兴事在我看来都有可能成为另一个让我不开心的原因；相反的如果在我高兴的时候，无论你怎么的使我生气，我都不会和你计较的。（呵呵~~是不是很白痴？）', '那天有人和我谈到星座，然后转头对我说：“瓶子，是不是水瓶座？”

说到瓶子顾名思义就是水瓶座，对我就是水瓶座的，所以将自己的名字取为瓶子。

女水瓶和男水瓶都是一样的，个性真的是太像了，所以也就有时候会互相吸引的原因。我就认识这么一个男水瓶，他很固执、任性还有那么一点点的孩子气，他会在心情不好的时候打开QQ将里面所有人都拉入黑名单，等过后再一个一个的问人家QQ从新加入，他还对那些被他删除了的人说是因为他心情不好才删了他们的，这最让人哭笑不得。他还会很反复无常，答应了你的事过后不到30分钟又会反悔不承认，让你一个人在那里生气，他却在一旁大笑，好像和他一点关系都没有，显得很绝情。而且他也会将自己的思想完完全全的表现在你的面前，不容你的反驳。可当你见到他的时候你完全不能把他和那个叫你气得咬牙切齿的人联想在一起，因为见他的时候他一路上都在笑，满脸上都是笑容。傻傻的看着你，你一点也生气不起来。这样的人真的和我太像了，简直就是自己的翻版，有时候真的会被他这样的性格所吸引。因为水瓶座的人都有颗猫般好奇的心，所以对于那种自己摸不透的人是最吸引他的。

其实我就是一个完全水瓶座的人，只要是瓶子应该具有的特性我都具有了。冷酷、绝情、怪异、独立、好奇、观察敏锐、思想新颖、有创意等，这些我都具备了。

水瓶座的我也具有了水瓶人的博爱，也因为这样身边到处都有很多喜欢自己的人，朋友很多；然而我最不能容许自己的感情的不明不白，就算是会伤了他人的心我也要将心里的感觉说出来，我宁愿绝情一点也不愿意暧昧不明；同样的，如果我喜欢一个人的话，那么我也会将这个心意表明出来，我不想拖泥带水，就算不被喜欢也好，我也会很自动的退下。这就是瓶子的个性不喜欢拖泥带水有什么就说什么，想什么就做什么，很果断。我也不去否认有很多人都被我这样的个性所伤害到，但是，也不可说我就没有一点的好处，至少我所知道的是我所有的朋友都很喜欢和我分享他们的心事，我就是有那种可以让人信任的力量，而我也真的很理性的去做许多事情。虽然自己也会被别人说不成熟，但是我对朋友很好，所以大家也很信任我。瓶子很重感情的。

自己是最知道自己的，自己是一个很感性的人，什么事情都会写在脸上，当我快乐、悲伤、犹豫、踌躇时，脸上都会出现这些心情对应的脸色；而且当我生气的时候，不管有什么高兴事在我看来都有可能成为另一个让我不开心的原因；相反的如果在我高兴的时候，无论你怎么的使我生气，我都不会和你计较的。（呵呵~~是不是很白痴？）', '漂流瓶，愿望的瓶子；花瓶，美丽的瓶子；暖瓶，温暖的瓶子。

而我，只是一支想要自我毁灭的瓶子，不要拦着我，让我自己修复。', '2002-08-15 00:55:00', 11, '20021029005029_bbsid_177899_board_1_b8ffd4b184.html', '20021029005029');
